+  gap: 28px;
+  padding: 16px;
+  width: 100%;
+}
+
+.stack-section.stack-center {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  gap: 14px;
+}
+
+.stack-section { width: 100%; }
+
+.stack-pile-wrap {
+  position: relative;
