+  pointer-events: none;
+  flex-shrink: 0;
+  left: auto !important;
+  top: auto !important;
+}
+.crd-discarded .crd-revealed-inner { padding: 4px; gap: 2px; }
+.crd-discarded .crd-cat { font-size: .5rem; letter-spacing: .5px; }
+.crd-discarded .crd-txt { font-size: .52rem; line-height: 1.2; }
+
+/* ============================================
+   STACK MODE LAYOUT
+   ============================================ */
+.stack-layout {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  gap: 28px;
+  padding: 16px;
+  width: 100%;
+}
+
+.stack-section.stack-center {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  gap: 14px;
+}
+
+.stack-section { width: 100%; }
+
+.stack-pile-wrap {
+  position: relative;
+  width: 230px;
+  height: 310px;
+}
+
+.stack-crd {
+  width: 210px !important;
+  height: 290px !important;
+}
+
+.stack-count {
+  font-size: .85rem;
+  color: var(--text2);
+  text-align: center;
+  letter-spacing: 1px;
+}
+
+.stack-pile {
+  position: relative;
+  width: 96px;
+  height: 138px;
+  margin: 0 auto 24px;
+  cursor: pointer;
+}
+.stack-pile .crd {
+  position: absolute !important;
+  left: 0 !important; top: 0 !important;
+  transition: transform .3s cubic-bezier(.23,1,.32,1) !important;
+}
+
+.discard-area {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 8px;
+  padding: 12px 0 4px;
+  max-width: min(900px, 96vw);
+  min-height: 40px;
+}
+
+/* Pulse animation */
+@keyframes pulse-card {
+  0%, 100% { box-shadow: 0 0 22px var(--glow), 3px 6px 18px rgba(0,0,0,.8); }
+  50%       { box-shadow: 0 0 44px rgba(229,9,20,.75), 3px 6px 18px rgba(0,0,0,.8); }
+}
+
+
+/* ============================================
+   TOP-UP MODAL — REDESIGN
+   ============================================ */
+.topup-box {
+  max-width: 450px;
+}
+
+.topup-grid {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  gap: 12px;
+  margin-bottom: 20px;
+}
+
+.topup-opt {
+  background: #141414;
+  border: 1px solid #242424;
+  border-radius: 14px;
+  padding: 20px 16px;
+  text-align: center;
+  cursor: pointer;
+  transition: all .22s cubic-bezier(.23,1,.32,1);
