+/* ============================================
+   TOUCH PICKER — สุ่มผู้เล่น
+   ============================================ */
+#touch-picker-ov {
+  position: fixed; inset: 0;
+  background: #000;
+  z-index: 800;
+  display: none;
+}
+#touch-picker-ov.show { display: block; }
+
+#touch-area {
+  width: 100%; height: 100%;
+  position: relative;
+  overflow: hidden;
+  user-select: none;
+  -webkit-user-select: none;
+  touch-action: none;
+    -webkit-touch-callout: none;
+  -webkit-user-select: none;
+}
+
+/* คำแนะนำตรงกลาง */
+#touch-instruction {
+  position: absolute;
+  top: 50%; left: 50%;
+  transform: translate(-50%, -50%);
+  text-align: center;
+  color: rgba(255,255,255,.25);
+  pointer-events: none;
+  z-index: 1;
+  transition: opacity .3s;
+}
+#touch-instruction i {
+  font-size: 3rem;
+  display: block;
+  margin-bottom: 12px;
+  color: var(--red);
+  opacity: .4;
+}
+#touch-instruction span {
+  font-size: 1rem;
+  font-family: "Kanit", sans-serif;
+  font-weight: 600;
+  letter-spacing: 1px;
+}
+#touch-instruction.hide { opacity: 0; }
+
+/* countdown ตรงกลาง */
+#touch-countdown {
+  position: absolute;
+  top: 28px; left: 50%;
+  transform: translateX(-50%);
+  font-family: "Kanit", sans-serif;
+  font-weight: 900;
+  font-size: 3.5rem;
+  color: var(--red);
+  text-shadow: 0 0 40px var(--glow), 0 0 80px rgba(229,9,20,.3);
+  pointer-events: none;
+  z-index: 5;
+  display: flex; align-items: center; gap: 10px;
+  background: rgba(0,0,0,.6);
+  border: 1px solid rgba(229,9,20,.3);
+  border-radius: 50px;
+  padding: 6px 28px;
+  backdrop-filter: blur(8px);
+  animation: cd-pulse .9s ease-in-out infinite;
+}
+@keyframes cd-pulse {
+  0%, 100% { transform: translateX(-50%) scale(1); opacity: 1; }
+  50%       { transform: translateX(-50%) scale(1.04); opacity: .85; }
+}
+
+/* dot แต่ละนิ้ว */
+.touch-dot {
+  position: absolute;
+  width: 80px; height: 80px;
+  border-radius: 50%;
+  transform: translate(-50%, -50%) scale(0);
+  display: flex; align-items: center; justify-content: center;
+  font-family: "Kanit", sans-serif;
+  font-weight: 900; font-size: 1.3rem;
+  color: #fff;
+  pointer-events: none;
+  transition: transform .2s cubic-bezier(.23,1,.32,1);
+  z-index: 3;
+}
+.touch-dot.show {
+  transform: translate(-50%, -50%) scale(1);
+}
+/* สีวนตามลำดับ */
+.touch-dot-0 { background: radial-gradient(circle, #e50914, #8b0000); box-shadow: 0 0 24px rgba(229,9,20,.6); }
+.touch-dot-1 { background: radial-gradient(circle, #ff6b35, #c0392b); box-shadow: 0 0 24px rgba(255,107,53,.6); }
+.touch-dot-2 { background: radial-gradient(circle, #e53935, #b71c1c); box-shadow: 0 0 24px rgba(229,57,53,.6); }
+.touch-dot-3 { background: radial-gradient(circle, #f44336, #7f0000); box-shadow: 0 0 24px rgba(244,67,54,.6); }
+.touch-dot-4 { background: radial-gradient(circle, #ff1744, #d50000); box-shadow: 0 0 24px rgba(255,23,68,.6); }
+.touch-dot-5 { background: radial-gradient(circle, #c62828, #4a0000); box-shadow: 0 0 24px rgba(198,40,40,.6); }
+
+/* dot ที่โดนเลือก */
+.touch-dot.picked {
+  transform: translate(-50%, -50%) scale(1.4) !important;
+  box-shadow: 0 0 60px var(--glow), 0 0 120px rgba(229,9,20,.5) !important;
+  animation: picked-bounce .4s ease !important;
+  z-index: 10;
+}
+@keyframes picked-bounce {
+  0%   { transform: translate(-50%, -50%) scale(1); }
+  50%  { transform: translate(-50%, -50%) scale(1.6); }
+  100% { transform: translate(-50%, -50%) scale(1.4); }
+}
+
+/* dot ที่ไม่ได้ถูกเลือก */
+.touch-dot.not-picked {
+  opacity: .2;
+  transform: translate(-50%, -50%) scale(0.7) !important;
+  transition: all .4s ease;
+}
+
+/* ripple รอบ dot ที่โดน */
+.touch-dot.picked::after {
+  content: "";
+  position: absolute; inset: -10px;
+  border-radius: 50%;
+  border: 3px solid var(--red);
+  animation: ripple-out .8s ease-out infinite;
+}
+@keyframes ripple-out {
+  0%   { transform: scale(1); opacity: .8; }
+  100% { transform: scale(2); opacity: 0; }
+}
+
+/* ข้อความผลด้านล่าง dot ที่โดน */
+.touch-dot-result {
+  position: absolute;
+  bottom: -36px; left: 50%;
+  transform: translateX(-50%);
+  white-space: nowrap;
+  font-size: .75rem;
+  font-weight: 700;
+  color: var(--red);
+  letter-spacing: 1px;
+  animation: fadeInUp .3s ease;
+}
+@keyframes fadeInUp {
+  from { opacity: 0; transform: translateX(-50%) translateY(8px); }
+  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
+}
+
+/* ปุ่มปิด */
+#touch-close-btn {
+  position: absolute;
+  top: 20px; right: 20px;
+  background: rgba(255,255,255,.08);
+  border: 1px solid rgba(255,255,255,.15);
+  color: rgba(255,255,255,.6);
+  padding: 9px 18px; border-radius: 8px;
+  font-family: "Kanit", sans-serif; font-size: .85rem;
+  cursor: pointer; transition: .2s;
+  display: flex; align-items: center; gap: 6px;
+  z-index: 10;
+}
+#touch-close-btn:hover {
+  background: rgba(229,9,20,.15);
+  border-color: rgba(229,9,20,.4);
+  color: #fff;
+}
+
+/* คำเตือนต้องการ 2 คน */
+#touch-warning {
+  position: absolute;
+  bottom: 80px; left: 50%;
+  transform: translateX(-50%);
+  background: rgba(229,9,20,.12);
+  border: 1px solid rgba(229,9,20,.3);
+  color: var(--red);
+  padding: 10px 20px; border-radius: 30px;
+  font-size: .85rem; font-family: "Kanit", sans-serif;
+  white-space: nowrap;
+  animation: fadeInUp .2s ease;
+  pointer-events: none;
+}
