+   components.css — Game, Cards, Result Modal
+   ============================================== */
+
+/* ---- GAME SCREEN ---- */
+
+* {
+  touch-action: manipulation;
+}
+
+#game-screen { display: none; min-height: 100vh; }
+
+.game-hdr {
+  display: flex; align-items: center; justify-content: space-between;
+  padding: 80px 36px 20px;
+  border-bottom: 1px solid #1c1c1c;
+}
+.g-deck-info { display: flex; align-items: center; gap: 12px; }
+.g-deck-ico  { width: 42px; height: 42px; border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 1.3rem; }
+.g-nm        { font-weight: 700; }
+.g-rm        { color: var(--text2); font-size: .82rem; display: flex; align-items: center; gap: 5px; margin-top: 2px; }
+.g-credit    { color: var(--gold); font-weight: 700; font-size: 1rem; display: flex; align-items: center; gap: 7px; }
+
+.table-area  { position: relative; min-height: calc(100vh - 200px); display: flex; flex-direction: column; align-items: center; justify-content: flex-start; padding: 24px 16px 80px; }
+.cards-wrap  {
+  position: relative;
+  width: min(900px, 96vw);
+  min-height: 500px;
+  margin: 0 auto;
+}
+
+/* ---- CARDS ---- */
+.crd {
+  position: absolute; width: 96px; height: 138px;
+  border-radius: 12px; cursor: pointer;
+  transition: all .28s cubic-bezier(.23,1,.32,1);
+  display: flex; align-items: center; justify-content: center;
+  user-select: none; transform-origin: center bottom;
+  background: repeating-linear-gradient(45deg, #1a0505, #1a0505 4px, #210707 4px, #210707 8px);
+  border: 1.5px solid #3a0808;
+  box-shadow: 3px 5px 16px rgba(0,0,0,.7), inset 0 1px 0 rgba(255,255,255,.04);
+}
+
+/* ---- ไพ่ขนาดเล็กสำหรับมือถือ ---- */
+.crd-sm {
+  width: 72px !important;
+  height: 104px !important;
+  border-radius: 9px !important;
+}
+.crd-sm .crd-back {
+  width: 56px !important;
+  height: 86px !important;
+  font-size: 1.4rem !important;
+}
+
+.crd-back {
+  width: 76px; height: 116px; border-radius: 8px;
+  display: flex; align-items: center; justify-content: center;
+  font-size: 1.9rem; color: var(--red);
+  background: linear-gradient(135deg, #2d0808, #4a0a0a);
+  border: 1px solid rgba(229,9,20,.35);
+}
+.crd-back i {
+  opacity: .4;
+}
+.crd.flipping { animation: flip .55s ease forwards; pointer-events: none; z-index: 100 !important; }
+@keyframes flip {
+  0%   { transform: rotateY(0) scale(1); }
+  50%  { transform: rotateY(90deg) scale(1.1); }
+  100% { transform: rotateY(0) scale(1); }
+}
+.crd.revealed {
+  background: linear-gradient(145deg, #200000, #0c0000);
+  border-color: var(--red);
+  box-shadow: 0 0 28px rgba(229,9,20,.25);
+  cursor: default; pointer-events: none;
+}
+.crd-revealed-inner {
+  display: flex; flex-direction: column; align-items: center; justify-content: center;
+  text-align: center; width: 100%; height: 100%; padding: 8px; gap: 4px;
+}
+.crd-cat { font-size: .6rem; color: var(--red); font-weight: 700; letter-spacing: 1px; }
+.crd-txt { font-size: .67rem; color: var(--text2); line-height: 1.3; }
+
+@media (max-width: 800px) {
+  .crd-cat { font-size: .72rem; }
+  .crd-txt { font-size: .82rem; line-height: 1.35; }
+}
+
+.cost-hint {
+  text-align: center; color: var(--text2); font-size: .88rem; margin-top: 18px;
+  display: flex; align-items: center; justify-content: center; gap: 7px;
+}
+.cost-hint .hl { color: var(--gold); font-weight: 700; }
+
+.overlay { position: fixed; inset: 0; background: rgba(0,0,0,.88); z-index: 500; display: none; align-items: center; justify-content: center; backdrop-filter: blur(7px); }
+.overlay.show { display: flex; }
+
+.res-card {
+  background: linear-gradient(145deg, #1c0404, #0d0000);
+  border: 1px solid var(--red2); border-radius: 20px;
+  padding: 64px 72px 56px; max-width: 700px; width: 90%;
+  text-align: center; position: relative;
+  box-shadow: 0 0 80px rgba(229,9,20,.28), 0 0 180px rgba(229,9,20,.08);
+  animation: slideUp .38s cubic-bezier(.23,1,.32,1);
+}
+.res-card::before {
+  content: ""; position: absolute; top: 0; left: 0; right: 0; height: 2.5px;
+  background: linear-gradient(90deg, transparent, var(--red), transparent);
+  border-radius: 20px 20px 0 0;
+}
+@keyframes slideUp {
+  from { transform: translateY(36px) scale(.95); opacity: 0; }
+  to   { transform: translateY(0) scale(1);     opacity: 1; }
+}
+.res-deck-lbl { font-size: .72rem; letter-spacing: 3px; color: var(--text3); text-transform: uppercase; margin-bottom: 12px; display: flex; align-items: center; gap: 6px; justify-content: center; }
+.res-ico-wrap { width: 130px; height: 130px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 14px; font-size: 3.6rem; }
+.res-cat  { font-family: "Kanit", sans-serif; font-weight: 800; font-size: 1.6rem; color: var(--red); letter-spacing: 4px; margin-bottom: 14px; }
+.res-txt  { font-size: 2.6rem; font-weight: 700; line-height: 1.4; margin-bottom: 28px; }
+.res-acts { display: flex; gap: 10px; justify-content: center; }
+
+.btn-close-r {
+  background: transparent; color: var(--text2); border: 1px solid #333;
+  padding: 11px 22px; border-radius: 8px;
+  font-family: "Kanit", sans-serif; cursor: pointer; transition: .2s;
+  display: flex; align-items: center; gap: 6px;
+}
+.btn-close-r:hover { border-color: #555; color: #fff; }
+
+.btn-next {
+  background: var(--red); color: #fff; border: none;
+  padding: 11px 28px; border-radius: 8px;
+  font-family: "Kanit", sans-serif; font-weight: 700; font-size: .95rem;
+  cursor: pointer; transition: .2s;
+  display: flex; align-items: center; gap: 7px;
+}
+.btn-next:hover { background: var(--red3); transform: translateY(-2px); }
+
+/* ---- RESPONSIVE ---- */
+@media (max-width: 580px) {
+  .game-hdr { padding: 80px 16px 18px; }
+  .res-card { padding: 32px 24px 28px; }
+  .res-txt { font-size: 2.5rem !important; }
+  /* .res-txt     { font-size: 800rem; margin-bottom: 800px; } */
+}
+
+/* ============================================
+   TOP-UP MODAL
+   ============================================ */
+.modal-box {
+  background: linear-gradient(145deg, #181818, #111);
+  border: 1px solid #282828;
+  border-radius: 20px;
+  padding: 38px;
+  max-width: 460px;
+  width: 90%;
+  position: relative;
+}
+.modal-x {
+  position: absolute; top: 12px; right: 14px;
+  background: none; border: none; color: var(--text2);
+  cursor: pointer; width: 30px; height: 30px;
+  display: flex; align-items: center; justify-content: center;
+  border-radius: 50%; transition: .2s; font-size: .95rem;
+}
+.modal-x:hover { background: #222; color: #fff; }
+
+.modal-ttl {
+  font-family: "Kanit", sans-serif;
+  font-weight: 900;
+  font-size: 1.7rem;
+  letter-spacing: 2px;
+  margin-bottom: 6px;
+  display: flex; align-items: center; gap: 10px;
+}
+.modal-ttl .r { color: var(--red); }
+.modal-sub { color: var(--text2); font-size: .85rem; margin-bottom: 22px; }
+
+.topup-grid {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  gap: 10px;
+  margin-bottom: 20px;
+}
+.topup-opt {
+  background: #1a1a1a;
+  border: 1px solid #262626;
+  border-radius: 12px;
+  padding: 16px;
+  text-align: center;
+  cursor: pointer;
+  transition: .2s;
+}
+.topup-opt:hover { border-color: var(--gold); box-shadow: 0 0 18px rgba(245,197,24,.08); }
+.topup-opt.sel   { border-color: var(--gold); background: rgba(245,197,24,.04); }
+
+.topup-opt .coins {
+  font-size: 1.1rem; font-weight: 700; color: var(--gold);
+  display: flex; align-items: center; gap: 6px; justify-content: center;
+}
+.topup-opt .price { font-size: .8rem; color: var(--text2); margin-top: 4px; }
+.topup-opt .bonus {
+  font-size: .72rem; color: #4caf50; font-weight: 600; margin-top: 3px;
+  display: flex; align-items: center; gap: 4px; justify-content: center;
+}
+
+.coming-banner {
+  background: rgba(229,9,20,.06);
+  border: 1px dashed rgba(229,9,20,.25);
+  border-radius: 10px;
+  padding: 12px 14px;
+  font-size: .82rem;
+  color: var(--text2);
+  display: flex; flex-direction: column; align-items: center; gap: 5px; text-align: center;
+}
+.coming-banner strong { color: var(--red); display: flex; align-items: center; gap: 6px; }
+
+.btn-free {
+  width: 100%; padding: 13px; margin-top: 14px;
+  background: var(--red); color: #fff; border: none;
+  border-radius: 8px;
+  font-family: "Kanit", sans-serif; font-weight: 700; font-size: 1rem;
+  cursor: pointer; transition: .2s;
+  display: flex; align-items: center; justify-content: center; gap: 8px;
+}
+.btn-free:hover { background: var(--red3); }
+
+@media (max-width: 580px) {
+  .topup-grid { grid-template-columns: 1fr; }
+  .modal-box  { padding: 28px 20px; }
+}
+
+/* ============================================
+   LAYOUT TOGGLE (scatter / stack)
+   ============================================ */
+.layout-toggle {
+  display: flex;
+  background: #111;
+  border: 1px solid #2a2a2a;
+  border-radius: 8px;
+  padding: 3px;
+  gap: 2px;
+}
+.lt-btn {
+  background: transparent;
+  border: none;
+  color: var(--text3);
+  width: 32px; height: 32px;
+  border-radius: 6px;
+  cursor: pointer;
+  display: flex; align-items: center; justify-content: center;
+  font-size: .9rem;
+  transition: all .2s;
+}
+.lt-btn:hover { color: var(--text2); background: #1a1a1a; }
+.lt-btn.act   { background: var(--red); color: #fff; }
+
+/* ============================================
+   DISCARD LABEL & ZONE (ใช้ร่วมกันทั้ง scatter & stack)
+   ============================================ */
+.discard-label {
+  font-size: .72rem;
+  color: var(--text3);
+  letter-spacing: 2px;
+  text-transform: uppercase;
+  margin-bottom: 6px;
+  display: flex;
+  align-items: center;
+  gap: 6px;
+}
+
+.discard-zone {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 8px;
+  justify-content: center;
+  padding: 8px 0 4px;
+  min-height: 60px;
+}
+
+/* ============================================
+   SCATTER MODE — discard section ใต้โต๊ะ
+   ============================================ */
+.discard-section {
+  width: min(900px, 96vw);
+  margin: 20px auto 0;
+  padding: 16px;
+  border-top: 1px solid #1c1c1c;
+}
+
+/* ============================================
+   CARD ที่เปิดแล้ว — เล็กลงใน discard zone
+   ============================================ */
+.crd-discarded {
+  position: relative !important;
+  width: 56px !important;
+  height: 80px !important;
+  border-radius: 7px !important;
+  cursor: default !important;
+  pointer-events: none;
+  flex-shrink: 0;
+  left: auto !important;
+  top: auto !important;
+}
+.crd-discarded .crd-revealed-inner { padding: 4px; gap: 2px; }
+.crd-discarded .crd-cat { font-size: .5rem; letter-spacing: .5px; }
+.crd-discarded .crd-txt { font-size: .52rem; line-height: 1.2; }
+
+/* ============================================
+   STACK MODE LAYOUT
+   ============================================ */
+.stack-layout {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  gap: 28px;
+  padding: 16px;
+  width: 100%;
+}
+
+.stack-section.stack-center {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  gap: 14px;
+}
+
+.stack-section { width: 100%; }
+
+.stack-pile-wrap {
+  position: relative;
+  width: 230px;
+  height: 310px;
+}
+
+.stack-crd {
+  width: 210px !important;
+  height: 290px !important;
+}
+
+.stack-count {
+  font-size: .85rem;
+  color: var(--text2);
+  text-align: center;
+  letter-spacing: 1px;
+}
+
+.stack-pile {
+  position: relative;
+  width: 96px;
+  height: 138px;
+  margin: 0 auto 24px;
+  cursor: pointer;
+}
+.stack-pile .crd {
+  position: absolute !important;
+  left: 0 !important; top: 0 !important;
+  transition: transform .3s cubic-bezier(.23,1,.32,1) !important;
+}
+
+.discard-area {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 8px;
+  padding: 12px 0 4px;
+  max-width: min(900px, 96vw);
+  min-height: 40px;
+}
+
+/* Pulse animation */
+@keyframes pulse-card {
+  0%, 100% { box-shadow: 0 0 22px var(--glow), 3px 6px 18px rgba(0,0,0,.8); }
+  50%       { box-shadow: 0 0 44px rgba(229,9,20,.75), 3px 6px 18px rgba(0,0,0,.8); }
+}
+
+
+/* ============================================
+   TOP-UP MODAL — REDESIGN
+   ============================================ */
+.topup-box {
+  max-width: 450px;
+}
+
+.topup-grid {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  gap: 12px;
+  margin-bottom: 20px;
+}
+
+.topup-opt {
+  background: #141414;
+  border: 1px solid #242424;
+  border-radius: 14px;
+  padding: 20px 16px;
+  text-align: center;
+  cursor: pointer;
+  transition: all .22s cubic-bezier(.23,1,.32,1);
+  overflow: visible; 
+  position: relative;
+}
+.topup-opt::before {
+  content: "";
+  position: absolute; top: 0; left: 0; right: 0; height: 1px;
+  background: linear-gradient(90deg, transparent, rgba(245,197,24,.2), transparent);
+  opacity: 0; transition: opacity .2s;
+}
+.topup-opt:hover {
+  border-color: rgba(245,197,24,.5);
+  transform: translateY(-3px);
+  box-shadow: 0 8px 28px rgba(245,197,24,.08);
+}
+.topup-opt:hover::before { opacity: 1; }
+.topup-opt.sel {
+  border-color: var(--gold);
+  background: rgba(245,197,24,.05);
+  box-shadow: 0 0 24px rgba(245,197,24,.12);
+}
+.topup-opt.sel::before { opacity: 1; }
+
+.topup-featured {
+  border-color: rgba(245,197,24,.35) !important;
+  background: linear-gradient(145deg, #1c1800, #141000) !important;
+}
+.topup-featured:hover {
+  border-color: var(--gold) !important;
+  box-shadow: 0 8px 32px rgba(245,197,24,.18) !important;
+}
+.topup-featured.sel {
+  box-shadow: 0 0 36px rgba(245,197,24,.2) !important;
+}
+
+.featured-badge {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  padding: 6px 14px;
+  white-space: nowrap;        /* ป้องกันข้อความตัดบรรทัด */
+  overflow: visible;
+  position: absolute;
+  top: -12px;
+  left: 16px;                 /* ชิดซ้าย แทน 50% */
+  transform: none;            /* เอา translateX(-50%) ออก */
+  background: linear-gradient(90deg, #FFD700, #FFA500);
+  color: #3c2900;
+  font-size: 14px;
+  font-weight: bold;
+  border-radius: 20px;
+  box-shadow: 0 2px 6px rgba(0,0,0,.2);
+}
+
+
+
+.pkg-coins {
+  font-size: 1.6rem; font-weight: 800; color: var(--gold);
+  display: flex; align-items: center; gap: 7px; justify-content: center;
+  line-height: 1;
+}
+.pkg-coins .fi { font-size: 1.3rem; }
+
+.pkg-price {
+  font-size: .88rem; color: var(--text2);
+  margin-top: 7px;
+}
+
+.pkg-bonus {
+  display: inline-flex; align-items: center; gap: 4px;
+  background: rgba(255, 189, 34, 0.1);
+  border: 1px solid rgba(255, 216, 19, 0.25);
+  border-radius: 20px;
+  padding: 3px 10px;
+  font-size: .72rem; color: #ffc400; font-weight: 600;
+  margin-top: 8px;
+}
+
+/* Coming banner — ปรับใหม่ */
+.coming-banner {
+  background: rgba(229,9,20,.05);
+  border: 1px solid rgba(229,9,20,.18);
+  border-radius: 10px;
+  padding: 13px 16px;
+  font-size: .82rem;
+  color: var(--text2);
+  display: flex; align-items: center; gap: 12px;
+  margin-bottom: 14px;
+}
+.coming-banner i {
+  color: var(--red); font-size: 1.1rem; flex-shrink: 0;
+}
+.coming-banner div {
+  display: flex; flex-direction: column; gap: 2px;
+}
+.coming-banner strong {
+  color: #fff; font-size: .85rem;
+}
+.coming-banner span {
+  font-size: .75rem; color: var(--text3);
+}
+
+.topup-balance {
+  display: flex; align-items: center; gap: 9px;
+  background: rgba(245,197,24,.06);
+  border: 1px solid rgba(245,197,24,.2);
+  border-radius: 10px;
+  padding: 10px 14px;
+  font-size: .99rem; color: var(--text2);
+  margin-bottom: 20px;
+  
+}
+.topup-balance span {
+  color: var(--gold); font-weight: 800; font-size: 1.1rem;
+  margin: 0 2px;
+  margin-left: auto;
+}
+
+
+/* ---- BIG CARD FOCUS LAYOUT ---- */
+.topup-row-small {
+  display: grid;
+  grid-template-columns: repeat(3, 1fr);
+  gap: 10px;
+}
+
+.topup-big {
+  padding: 20px 22px !important;
+  margin-top: 2px;
+}
+
+.pkg-big-wrap {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  gap: 10px;
+  margin-top: 12px;
+}
+
+.pkg-coins-big {
+  font-size: 3rem !important;
+  font-weight: 900 !important;
+  gap: 10px !important;
+}
+.pkg-coins-big .fi { font-size: 2.4rem !important; }
+
+.pkg-big-right {
+  display: flex;
+  flex-direction: column;
+  align-items: flex-start;
+  gap: 6px;
+}
+
+.pkg-price-big {
+  font-size: 1.5rem;
+  font-weight: 800;
+  color: #fff;
+}
+
+.pkg-per {
+  font-size: .72rem;
+  color: var(--text3);
+  letter-spacing: .5px;
+}
+
+/* override grid เดิมสำหรับ big layout */
+.topup-grid {
+  display: flex !important;
+  flex-direction: column;
+  gap: 10px;
+  margin-bottom: 20px;
+}
+
+@media (max-width: 400px) {
+  .topup-row-small { grid-template-columns: repeat(3, 1fr); }
+  .pkg-coins-big   { font-size: 2.2rem !important; }
+}
+
+/* ============================================
+   MOBILE FIXES — game header
+   ============================================ */
+@media (max-width: 580px) {
+  .game-hdr {
+    padding: 68px 12px 14px;
+    flex-wrap: wrap;
+    gap: 10px;
+  }
+  .g-deck-ico  { width: 34px; height: 34px; font-size: 1rem; }
+  .g-nm        { font-size: .85rem; }
+  .g-rm        { font-size: .72rem; }
+  .g-credit    { font-size: .88rem; }
+  .g-layout-label { display: none; }
+
+  .table-area  { padding: 16px 8px 90px; }
+  .cards-wrap  { width: 100%; }
+
+  .cost-hint   { font-size: .78rem; gap: 5px; }
+
+  /* result modal */
+  .res-card    { padding: 28px 18px 24px; width: 95%; }
+  .res-ico-wrap{ width: 70px; height: 70px; font-size: 2rem; }
+  .res-cat     { font-size: 1rem; letter-spacing: 2px; }
+  .res-txt     { font-size: 1.2rem; margin-bottom: 20px; }
+  .res-acts    { flex-direction: column; gap: 8px; }
+  .btn-close-r,
+  .btn-next    { width: 100%; justify-content: center; }
+
+  /* stack mode */
+  .stack-pile-wrap { width: 180px; height: 250px; }
+  .stack-crd       { width: 160px !important; height: 225px !important; }
+
+  /* topup modal */
+  .topup-row-small { grid-template-columns: repeat(3,1fr); gap: 7px; }
+  .modal-box       { padding: 24px 16px; width: 96%; }
+  .modal-ttl       { font-size: 1.4rem; }
+  .pkg-coins       { font-size: 1.2rem; }
+  .pkg-coins-big   { font-size: 2rem !important; }
+  .pkg-price-big   { font-size: 1.2rem; }
+  .featured-badge  { font-size: 11px; padding: 4px 10px; }
+}
+
+/* ============================================
+   HISTORY DRAWER — ประวัติไพ่ที่เปิดไปแล้ว
+   ============================================ */
+#hist-drawer-overlay {
+  position: fixed; inset: 0;
+  background: rgba(0,0,0,.7);
+  z-index: 490;
+  display: none;
+  backdrop-filter: blur(4px);
+}
+#hist-drawer-overlay.show { display: block; }
+
+#hist-drawer {
+  position: fixed;
+  bottom: 0; left: 0; right: 0;
+  z-index: 495;
+  background: linear-gradient(180deg, #161616, #111);
+  border-top: 1px solid #2a2a2a;
+  border-radius: 20px 20px 0 0;
+  padding: 0 0 env(safe-area-inset-bottom, 0);
+  transform: translateY(100%);
