+}
+#touch-instruction.hide { opacity: 0; }
+
+/* countdown ตรงกลาง */
+#touch-countdown {
+  position: fixed;
+  inset: 0;
+  display: none;
+  align-items: center;
+  justify-content: center;
+  font-size: clamp(6rem, 30vw, 12rem);
+  font-weight: 900;
+  color: var(--red);
+  text-shadow: 0 0 60px var(--red), 0 0 120px var(--red);
+  z-index: 999;
+  pointer-events: none;
+  animation: cd-pulse 1s ease-in-out infinite;
