+/* dot แต่ละนิ้ว */
+.touch-dot {
+  position: absolute;
+  width: 80px; height: 80px;
+  border-radius: 50%;
+  transform: translate(-50%, -50%) scale(0);
+  display: flex; align-items: center; justify-content: center;
+  font-family: "Kanit", sans-serif;
+  font-weight: 900; font-size: 1.3rem;
+  color: #fff;
+  pointer-events: none;
