+.touch-dot.show {
+  transform: translate(-50%, -50%) scale(1);
+}
+/* สีวนตามลำดับ */
+.touch-dot-0 { background: radial-gradient(circle, #e50914, #8b0000); box-shadow: 0 0 24px rgba(229,9,20,.6); }
+.touch-dot-1 { background: radial-gradient(circle, #ff6b35, #c0392b); box-shadow: 0 0 24px rgba(255,107,53,.6); }
+.touch-dot-2 { background: radial-gradient(circle, #e53935, #b71c1c); box-shadow: 0 0 24px rgba(229,57,53,.6); }
+.touch-dot-3 { background: radial-gradient(circle, #f44336, #7f0000); box-shadow: 0 0 24px rgba(244,67,54,.6); }
+.touch-dot-4 { background: radial-gradient(circle, #ff1744, #d50000); box-shadow: 0 0 24px rgba(255,23,68,.6); }
+.touch-dot-5 { background: radial-gradient(circle, #c62828, #4a0000); box-shadow: 0 0 24px rgba(198,40,40,.6); }
+
+/* dot ที่โดนเลือก */
+.touch-dot.picked {
+  width: 120px !important;
+  height: 120px !important;
+  font-size: 2.2rem !important;
+  background: var(--red) !important;
+  box-shadow: 0 0 0 12px rgba(255,50,50,0.25),
+              0 0 60px var(--red),
+              0 0 120px var(--red) !important;
+  z-index: 999 !important;
+  transition: all 0.4s cubic-bezier(.23,1,.32,1) !important;
+}
+
+@keyframes picked-bounce {
+  0%   { transform: translate(-50%, -50%) scale(1); }
+  50%  { transform: translate(-50%, -50%) scale(1.6); }
+  100% { transform: translate(-50%, -50%) scale(1.4); }
+}
+
+/* dot ที่ไม่ถูกเลือก */
+.touch-dot.not-picked {
+  opacity: 0.15 !important;
+  transform: translate(-50%, -50%) scale(0.7) !important;
+  transition: all 0.4s ease !important;
+}
+
+/* ripple รอบ dot ที่โดน */
+.touch-dot.picked::after {
+  content: "";
+  position: absolute; inset: -10px;
+  border-radius: 50%;
+  border: 3px solid var(--red);
+  animation: ripple-out .8s ease-out infinite;
+}
+@keyframes ripple-out {
+  0%   { transform: scale(1); opacity: .8; }
+  100% { transform: scale(2); opacity: 0; }
+}
+
+/* ข้อความใต้ dot */
+.touch-dot-result {
+  position: absolute;
+  bottom: -2rem;
+  left: 50%;
+  transform: translateX(-50%);
+  white-space: nowrap;
+  font-size: 1rem;
+  font-weight: 700;
+  color: #fff;
